/* CREATE TABLE dbo.FactProduction (
    FactProductionKey   INT             IDENTITY(1,1)   PRIMARY KEY,

    -- Foreign Keys (Dimension Tables)
    DateKey             INT             NOT NULL,
    ProductKey          INT             NOT NULL,
    FactoryKey          INT             NOT NULL,
    RegionKey           INT             NOT NULL,
    SupplierKey         INT             NOT NULL,
    ChannelKey          INT             NOT NULL,

    -- Measures
    UnitsProduced       DECIMAL(18,2)   NOT NULL,
    UnitsGood           DECIMAL(18,2)   NOT NULL,
    UnitsScrap          DECIMAL(18,2)   NOT NULL,
    ProductionHours     DECIMAL(18,2)   NOT NULL,
    DowntimeHours       DECIMAL(18,2)   NOT NULL,
    StandardCost        DECIMAL(18,2)   NOT NULL,
    ActualCost          DECIMAL(18,2)   NOT NULL,

    -- Foreign Key Constraints
    CONSTRAINT FK_FactProduction_Date
        FOREIGN KEY (DateKey)     REFERENCES DimDate(DateKey),

    CONSTRAINT FK_FactProduction_Product
        FOREIGN KEY (ProductKey)  REFERENCES DimProduct(ProductKey),

    CONSTRAINT FK_FactProduction_Factory
        FOREIGN KEY (FactoryKey)  REFERENCES DimFactory(FactoryKey),

    CONSTRAINT FK_FactProduction_Region
        FOREIGN KEY (RegionKey)   REFERENCES DimRegion(RegionKey),

    CONSTRAINT FK_FactProduction_Supplier
        FOREIGN KEY (SupplierKey) REFERENCES DimSupplier(SupplierKey),

    CONSTRAINT FK_FactProduction_Channel
        FOREIGN KEY (ChannelKey)  REFERENCES DimChannel(ChannelKey)
);
*/

